// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface attachedContextLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        contextItems: (
            providers: Record<string, AttachedContextItem[]>,
            dismissedKeys: Record<string, true>
        ) => AttachedContextItem[]
        hasContext: (contextItems: AttachedContextItem[]) => boolean
    }
}

export type attachedContextLogicType = MakeLogicType<
    attachedContextLogicValues,
    attachedContextLogicActions,
    Record<string, any>,
    attachedContextLogicMeta
>

/**
 * Global, unkeyed store of attached context for the PostHog AI surface. One mechanism only — a
 * registry of context providers, so registration and removal are symmetric and trivial. Each
 * provider (a mounted hook/component, or a future @-mention picker) owns a stable `providerId` and
 * upserts its items; `contextItems` flattens and dedupes across providers.
 *
 * A consumer reads `contextItems` at send time and wraps the outgoing message with the
 * trusted/untrusted context blocks (`utils/posthogContextBlock`). Nothing here is keyed by conversation —
 * the on-screen context is global to the app at any instant.
 *
 * This store also keeps the sent-context bookkeeping, two layers keyed by task id (task-scoped, not
 * run-scoped, so the dedupe survives a terminal-run send re-pointing the consumer to a fresh run):
 *
 * - `sentContextKeysByTask` — which non-text refs the send paths already wrapped into a message this
 *   session, marked right after a successful send. Covers the send→echo in-flight window, but is
 *   in-memory only: a reload, another tab, or a teammate's browser starts empty.
 * - `seenContextLinesByTask` — the durable layer: rendered block lines reconstructed from the run
 *   log itself. `runStreamLogic` records the lines of every context block found in a persisted or
 *   echoed user message (the `logs/` snapshot replays the task's full resume chain), and the send
 *   paths prune any item whose `contextItemLine` is already recorded. This mirrors the backend's
 *   `_collect_seen_entity_refs`/`prune_repeated_entity_refs`, which dedupe from persisted logs
 *   across a task's whole resume chain.
 */
export const attachedContextLogic = kea<attachedContextLogicType>([
    path(['products', 'posthog_ai', 'frontend', 'logics', 'attachedContextLogic']),

    actions({
        /** Idempotent upsert — re-register the same `providerId` to update its items. */
        registerContext: (providerId: string, items: AttachedContextItem[]) => ({ providerId, items }),
        deregisterContext: (providerId: string) => ({ providerId }),
        /** Record context item keys already wrapped into a message sent for `taskId`. */
        markContextSent: (taskId: string, keys: string[]) => ({ taskId, keys }),
        /** Record rendered context-block lines observed in `taskId`'s run log (see `seenContextLinesByTask`). */
        markContextLinesSeen: (taskId: string, lines: string[]) => ({ taskId, lines }),
        /**
         * Hide one item (by `attachedContextItemKey`) regardless of which provider contributed it —
         * the user closing a chip must stick even when the provider re-registers the same item
         * (e.g. the scene bridge upserting on every scene read).
         */
        dismissContext: (key: string) => ({ key }),
        undismissContext: (key: string) => ({ key }),
    }),

    reducers({
        providers: [
            {} as Record<string, AttachedContextItem[]>,
            {
                registerContext: (state, { providerId, items }) => ({ ...state, [providerId]: items }),
                deregisterContext: (state, { providerId }) => {
                    if (!(providerId in state)) {
                        return state
                    }
                    const { [providerId]: _dropped, ...rest } = state
                    return rest
                },
            },
        ],
        // Per-task set of `attachedContextItemKey`s already wrapped into a sent message. Append-only for
        // the session: entity refs sent once anywhere in a task's resume chain stay pruned from later sends.
        sentContextKeysByTask: [
            {} as Record<string, string[]>,
            {
                markContextSent: (state, { taskId, keys }) => {
                    if (keys.length === 0) {
                        return state
                    }
                    const existing = state[taskId] ?? []
                    const added = keys.filter((key) => !existing.includes(key))
                    if (added.length === 0) {
                        return state
                    }
                    return { ...state, [taskId]: [...existing, ...added] }
                },
            },
        ],
        // Per-task set of rendered context-block lines observed in the task's run log (replay or live
        // echo). The durable dedupe layer: unlike `sentContextKeysByTask` it is reconstructed from the
        // persisted resume-chain history on every open, so it survives reloads and other sessions.
        seenContextLinesByTask: [
            {} as Record<string, string[]>,
            {
                markContextLinesSeen: (state, { taskId, lines }) => {
                    if (lines.length === 0) {
                        return state
                    }
                    const existing = state[taskId] ?? []
                    const added = lines.filter((line) => !existing.includes(line))
                    if (added.length === 0) {
                        return state
                    }
                    return { ...state, [taskId]: [...existing, ...added] }
                },
            },
        ],
        dismissedKeys: [
            {} as Record<string, true>,
            {
                dismissContext: (state, { key }) => ({ ...state, [key]: true as const }),
                undismissContext: (state, { key }) => {
                    if (!(key in state)) {
                        return state
                    }
                    const { [key]: _dropped, ...rest } = state
                    return rest
                },
            },
        ],
    }),

    selectors({
        // Flattened across providers, deduped by `${type}:${key ?? value}` (first writer wins).
        // Items with neither `key` nor `value` carry no payload and are dropped, as are dismissed keys.
        contextItems: [
            (s) => [s.providers, s.dismissedKeys],
            (
                providers: Record<string, AttachedContextItem[]>,
                dismissedKeys: Record<string, true>
            ): AttachedContextItem[] => {
                const seen = new Set<string>()
                const out: AttachedContextItem[] = []
                for (const items of Object.values(providers)) {
                    for (const item of items) {
                        const hasKey = item.key !== undefined && item.key !== null && item.key !== ''
                        const hasValue = item.value !== undefined && item.value !== ''
                        if (!hasKey && !hasValue) {
                            continue
                        }
                        const key = attachedContextItemKey(item)
                        if (seen.has(key) || dismissedKeys[key]) {
                            continue
                        }
                        seen.add(key)
                        out.push(item)
                    }
                }
                return out
            },
        ],
        hasContext: [
            (s) => [s.contextItems],
            (contextItems: AttachedContextItem[]): boolean => contextItems.length > 0,
        ],
    }),
])
